+import React, { useEffect, useRef, useState } from "react";
+
+import type { Castle, Agent, Room } from "../types";
+
+import "./Minimap.css";
+
+interface MinimapProps {
+  castle: Castle;
+  agents: Agent[];
+  activeRoomIds: Set<string>;
+  onRoomClick: (roomId: string) => void;
+}
+
+// Helper to get room position and size in minimap coordinates
+// We assume castle.rooms have x,y,width,height in some coordinate system
+// We scale to fit minimap size
+
+const MINIMAP_WIDTH = 200;
+const MINIMAP_HEIGHT = 150;
+
+export function Minimap({ castle, agents, activeRoomIds, onRoomClick }: MinimapProps) {
+  const [scale, setScale] = useState(1);
+  const [offsetX, setOffsetX] = useState(0);
+  const [offsetY, setOffsetY] = useState(0);
+  const svgRef = useRef<SVGSVGElement>(null);
+
+  // Calculate bounding box of castle rooms
+  const rooms = castle.rooms;
+  const minX = Math.min(...rooms.map((r) => r.x));
+  const minY = Math.min(...rooms.map((r) => r.y));
+  const maxX = Math.max(...rooms.map((r) => r.x + r.width));
+  const maxY = Math.max(...rooms.map((r) => r.y + r.height));
+
+  useEffect(() => {
+    const castleWidth = maxX - minX;
+    const castleHeight = maxY - minY;
+    const scaleX = MINIMAP_WIDTH / castleWidth;
+    const scaleY = MINIMAP_HEIGHT / castleHeight;
+    const newScale = Math.min(scaleX, scaleY);
+    setScale(newScale);
+    // center offset
+    setOffsetX(-minX);
+    setOffsetY(-minY);
+  }, [minX, minY, maxX, maxY]);
+
+  // Map room coordinates to minimap coords
+  function roomToMinimap(r: Room) {
+    return {
+      x: (r.x + offsetX) * scale,
+      y: (r.y + offsetY) * scale,
+      width: r.width * scale,
+      height: r.height * scale,
+    };
+  }
+
+  // Get agents in a room
+  function agentsInRoom(roomId: string) {
+    return agents.filter((a) => a.roomId === roomId);
+  }
+
+  return (
+    <svg
+      ref={svgRef}
+      className="minimap"
+      width={MINIMAP_WIDTH}
+      height={MINIMAP_HEIGHT}
+      viewBox={`0 0 ${MINIMAP_WIDTH} ${MINIMAP_HEIGHT}`}
+      aria-label="Castle minimap"
+    >
+      {rooms.map((room) => {
+        const pos = roomToMinimap(room);
+        const isActive = activeRoomIds.has(room.id);
+        const roomAgents = agentsInRoom(room.id);
+        return (
+          <g
+            key={room.id}
+            className={`minimap-room ${isActive ? "active" : ""}`}
+            onClick={() => onRoomClick(room.id)}
+            tabIndex={0}
+            role="button"
+            aria-label={`Room ${room.name}`}
+            onKeyDown={(e) => {
+              if (e.key === "Enter" || e.key === " ") {
+                onRoomClick(room.id);
+                e.preventDefault();
+              }
+            }}
+          >
+            <rect
+              x={pos.x}
+              y={pos.y}
+              width={pos.width}
+              height={pos.height}
+              fill="#ddd"
+              stroke="#555"
+              strokeWidth={1}
+              rx={3}
+              ry={3}
+            />
+            <title>{room.name}</title>
+            {roomAgents.map((agent, i) => {
+              // Position dots inside room rect, spaced horizontally
+              const dotRadius = 3;
+              const spacing = dotRadius * 2 + 2;
+              const dotX = pos.x + 5 + i * spacing;
+              const dotY = pos.y + pos.height / 2;
+              return (
+                <circle
+                  key={agent.id}
+                  cx={dotX}
+                  cy={dotY}
+                  r={dotRadius}
+                  fill={agent.color || "#f00"}
+                  stroke="#333"
+                  strokeWidth={0.5}
+                  className="minimap-agent-dot"
+                >
+                  <title>{agent.name}</title>
+                </circle>
+              );
+            })}
+          </g>
+        );
+      })}
+    </svg>
+  );
+}
