+  50% {
+    filter: drop-shadow(0 0 8px #3399ff);
+  }
+  100% {
+    filter: drop-shadow(0 0 0 #3399ff);
+  }
+}
+
+.minimap-agent-dot {
+  transition: r 0.2s ease;
+}
+
+.minimap-agent-dot:hover {
+  r: 5;
+  stroke-width: 1.5;
+  stroke: #000;
